const rows = $input.all().map(i => i.json);
const wy = $now.toFormat('kkkk');
const ww = $now.toFormat('WW');
const week = `${wy}-W${ww}`;
const title = `${wy}년 WW${ww} 주간 회의`;
const today = $now.toFormat('yyyy-MM-dd');
const v = (s) => (s && String(s).trim()) ? s : '-';
const authors = rows.map(r => r.author).join(', ') || '(없음)';

const rich = (t) => [{ type: 'text', text: { content: (t || '').slice(0, 1990) } }];
const H = (t) => ({ object: 'block', type: 'heading_2', heading_2: { rich_text: rich(t) } });
const P = (t) => ({ object: 'block', type: 'paragraph', paragraph: { rich_text: rich(t) } });
const Callout = (t) => ({ object: 'block', type: 'callout', callout: { rich_text: rich(t), icon: { emoji: '📌' } } });
const Divider = () => ({ object: 'block', type: 'divider', divider: {} });

// 페이지 상단 메타데이터(문서 위에 따로 표시)
const meta = `주차: ${week}
생성일: ${today}
취합 인원: ${rows.length}명
작성자: ${authors}`;

const children = [ Callout(meta), Divider(), H('팀원별 보고') ];
if (rows.length === 0) {
  children.push(P('이번 주 제출된 보고가 없습니다.'));
} else {
  for (const r of rows) {
    children.push(P(`👤 ${r.author}
• 팀 할일(정기): ${v(r.teamTasks)}
• 프로젝트 활동: ${v(r.projectActivity)}
• PWM 활동: ${v(r.pwmActivity)}
• 휴가 계획: ${v(r.vacationPlan)}`));
  }
}

const body = {
  parent: { page_id: 'REPLACE_WITH_PARENT_PAGE_ID' },  // ← 부모 페이지 id로 교체
  properties: { title: { title: rich(title) } },        // 페이지 부모일 땐 키가 항상 'title'
  children,
};

return [{ json: { title, count: rows.length, body } }];

const info = $('회의 정보 조립 (Notion)').first().json;
const res = $input.first().json;
const pageUrl = res && res.url ? res.url : '(URL 확인 불가)';
const text = `✅ Notion 주간회의 회의록 작성 완료
• ${info.title} (${info.count}명 취합)
• ${pageUrl}`;
return [{ json: { slackBody: { channel: 'U07TD4739UG', text } } }];
